class Solution {
    public boolean canIWin(int maxChoosableInteger, int desiredTotal) {
        if (desiredTotal <= 0) return true;
        int sum = (1 + maxChoosableInteger) * maxChoosableInteger / 2;
        if (sum < desiredTotal) return false;
        if (sum == desiredTotal) return maxChoosableInteger % 2 == 1;
        Boolean[] memo = new Boolean[1 << maxChoosableInteger];
        return helper(maxChoosableInteger, desiredTotal, 0, memo);
    }

    private boolean helper(int maxChoosableInteger, int desiredTotal, int state, Boolean[] memo) {
        if (memo[state] != null) return memo[state];
        for (int i = 1; i <= maxChoosableInteger; i++) {
            int bit = 1 << (i - 1);
            if ((state & bit) == 0) {
                if (i >= desiredTotal || !helper(maxChoosableInteger, desiredTotal - i, state | bit, memo)) {
                    memo[state] = true;
                    return true;
                }
            }
        }
        memo[state] = false;
        return false;
    }
}
